    assert all(isinstance(value, int) for value in (remaining_ms, phase_budget_ms, cleanup_reserve_ms))
    if remaining_ms <= 0 or phase_budget_ms <= 0 or cleanup_reserve_ms < 0:
        return {"start": False, "usable_ms": 0}
